class Solution:
    def minSensors(self, n, m, k):
        side = 2 * k + 1
        rows = (n + side - 1) // side
        cols = (m + side - 1) // side
        return rows * cols

solutions.python:
class Solution:
    def minSensors(self, n, m, k):
        side = 2 * k + 1
        import math
        return math.ceil(n / side) * math.ceil(m / side)

